			BeadID:    "ddx-reconcile",
			Phase:     "running",
			StartedAt: time.Now().UTC().Add(-3 * time.Hour),
		},
	}
	require.NoError(t, m.writeRecord(dir, stale))

	if isPIDAlive(9999996) {
