191		data, err := json.MarshalIndent(state, "", "  ")
192		if err != nil {
193			return err
194		}
195		data = append(data, '\n')
196		tmp := s.desiredStatePath() + ".tmp"
197		if err := os.WriteFile(tmp, data, 0o644); err != nil {
198			return err
199		}
200		return os.Rename(tmp, s.desiredStatePath())
201	}
