203	// LoadDesiredState reads and validates the durable desired-state file.
204	func (s *WorkerSupervisor) LoadDesiredState() (WorkerDesiredState, error) {
205		if s == nil || s.manager == nil {
206			return WorkerDesiredState{}, fmt.Errorf("worker supervisor is not configured")
207		}
208	
209		data, err := os.ReadFile(s.desiredStatePath())
210		if err != nil {
211			return WorkerDesiredState{}, err
212		}
213	
214		var state WorkerDesiredState
215		if err := json.Unmarshal(data, &state); err != nil {
216			return WorkerDesiredState{}, err
217		}
218		if state.ProjectRoot != "" && state.ProjectRoot != s.manager.projectRoot {
219			return WorkerDesiredState{}, fmt.Errorf("worker desired state: project_root %q does not match manager root %q", state.ProjectRoot, s.manager.projectRoot)
220		}
221		state.ApplyDefaults(s.manager.projectRoot)
222		if err := state.Validate(); err != nil {
223			return WorkerDesiredState{}, err
224		}
225		return state, nil
226	}
