286	func (s *WorkerSupervisor) snapshotWorkers(projectRoot string) (active []WorkerRecord, running []WorkerRecord, terminals []WorkerRecord, staleIDs []string, err error) {
287		if s == nil || s.manager == nil {
288			return nil, nil, nil, nil, fmt.Errorf("worker supervisor is not configured")
289		}
290	
291		entries, err := os.ReadDir(s.manager.rootDir)
292		if err != nil {
293			return nil, nil, nil, nil, err
294		}
295	
296		for _, entry := range entries {
297			if !entry.IsDir() {
298				continue
299			}
300	
301			dir := filepath.Join(s.manager.rootDir, entry.Name())
302			rec, readErr := s.manager.readRecord(dir)
303			if readErr != nil {
304				continue
305			}
306			if rec.Kind != "work" {
307				continue
308			}
309			if rec.ProjectRoot != "" && rec.ProjectRoot != projectRoot {
310				continue
311			}
312	
313			hasHandle := s.manager.hasWorkerHandle(rec.ID)
314			switch rec.State {
315			case "running", "stopping":
316				if !hasHandle {
317					staleIDs = append(staleIDs, rec.ID)
318					continue
319				}
320				active = append(active, rec)
321				if rec.State == "running" {
322					running = append(running, rec)
323				}
324			default:
325				terminals = append(terminals, rec)
326			}
327		}
328	
329		sort.Slice(active, func(i, j int) bool {
330			if active[i].StartedAt.Equal(active[j].StartedAt) {
331				return active[i].ID > active[j].ID
332			}
333			return active[i].StartedAt.After(active[j].StartedAt)
334		})
335		sort.Slice(running, func(i, j int) bool {
336			if running[i].StartedAt.Equal(running[j].StartedAt) {
337				return running[i].ID > running[j].ID
338			}
339			return running[i].StartedAt.After(running[j].StartedAt)
340		})
341	
342		return active, running, terminals, staleIDs, nil
343	}
