345	func (s *WorkerSupervisor) recordTerminalHistory(terminals []WorkerRecord, now time.Time) {
346		s.mu.Lock()
347		defer s.mu.Unlock()
348	
349		if len(terminals) == 0 {
350			return
351		}
352	
353		if s.seenTerminals == nil {
354			s.seenTerminals = map[string]time.Time{}
355		}
356		if s.blockedTerminals == nil {
357			s.blockedTerminals = map[string]string{}
358		}
359	
360		for _, rec := range terminals {
361			if _, seen := s.seenTerminals[rec.ID]; seen {
362				continue
363			}
364			s.seenTerminals[rec.ID] = now
365			if isExpectedTerminalWorker(rec) {
366				continue
367			}
368			if isRestartBlockedWorker(rec) {
369				s.blockedTerminals[rec.ID] = firstNonEmpty(
370					rec.ReapReason,
371					rec.Status,
372					rec.LastError,
373					rec.Error,
374					rec.State,
375				)
376				continue
377			}
378			ts := rec.FinishedAt
379			if ts.IsZero() {
380				ts = rec.StartedAt
381			}
382			if ts.IsZero() {
383				ts = now
384			}
385			s.restartEvents = append(s.restartEvents, ts)
386		}
387	
388		s.restartEvents = pruneTimeWindow(s.restartEvents, now, time.Hour)
389	}
