391	func (s *WorkerSupervisor) stopNewestExcess(running []WorkerRecord, excess int) error {
392		if excess <= 0 {
393			return nil
394		}
395	
396		limit := excess
397		if len(running) < limit {
398			limit = len(running)
399		}
400		for i := 0; i < limit; i++ {
401			if err := s.manager.Stop(running[i].ID); err != nil {
402				return err
403			}
404		}
405		return nil
406	}
