408	func (s *WorkerSupervisor) canStartMore(state WorkerDesiredState, now time.Time) bool {
409		s.mu.Lock()
410		defer s.mu.Unlock()
411	
412		if len(s.blockedTerminals) > 0 {
413			return false
414		}
415	
416		events := pruneTimeWindow(s.restartEvents, now, time.Hour)
417		s.restartEvents = events
418		if !state.Restart.Enabled {
419			return len(events) == 0
420		}
421		if len(events) == 0 {
422			return true
423		}
424		if len(events) > state.Restart.MaxRestartsPerHour {
425			return false
426		}
427		delay := restartBackoffDelay(state.Restart, len(events))
428		last := events[0]
429		for _, ts := range events[1:] {
430			if ts.After(last) {
431				last = ts
432			}
433		}
434		return !now.Before(last.Add(delay))
435	}
436	
437	func restartBackoffDelay(policy WorkerRestartPolicy, recentEvents int) time.Duration {
438		delay := policy.Backoff.Duration
439		if delay <= 0 {
440			return 0
441		}
442		if recentEvents <= 1 {
443			if policy.BackoffMax.Duration > 0 && delay > policy.BackoffMax.Duration {
444				return policy.BackoffMax.Duration
445			}
446			return delay
447		}
448	
449		shift := recentEvents - 1
450		for shift > 0 {
451			if delay > time.Duration(1<<62) {
452				delay = policy.BackoffMax.Duration
453				break
454			}
455			delay *= 2
456			shift--
457			if policy.BackoffMax.Duration > 0 && delay >= policy.BackoffMax.Duration {
458				delay = policy.BackoffMax.Duration
459				break
460			}
461		}
462		if policy.BackoffMax.Duration > 0 && delay > policy.BackoffMax.Duration {
463			delay = policy.BackoffMax.Duration
464		}
465		return delay
466	}
467	
468	func pruneTimeWindow(times []time.Time, now time.Time, window time.Duration) []time.Time {
469		if window <= 0 || len(times) == 0 {
470			return append([]time.Time(nil), times...)
471		}
472		cutoff := now.Add(-window)
473		out := make([]time.Time, 0, len(times))
474		for _, ts := range times {
475			if ts.Before(cutoff) {
476				continue
477			}
478			out = append(out, ts)
479		}
480		return out
481	}
