483	func isExpectedTerminalWorker(rec WorkerRecord) bool {
484		switch rec.State {
485		case "stopped":
486			return true
487		case "exited":
488			switch rec.Status {
489			case "success", "no_ready_work":
490				return true
491			}
492		}
493		return false
494	}
495	
496	func isRestartBlockedWorker(rec WorkerRecord) bool {
497		fields := []string{
498			rec.ReapReason,
499			rec.Status,
500			rec.LastError,
501			rec.Error,
502			rec.State,
503		}
504		for _, field := range fields {
505			lower := strings.ToLower(field)
506			if strings.Contains(lower, "operator_attention") ||
507				strings.Contains(lower, "dirty_root") ||
508				strings.Contains(lower, "dirty-root") ||
509				strings.Contains(lower, "dirty root") {
510				return true
511			}
512		}
513		return false
514	}
515	
516	func firstNonEmpty(values ...string) string {
517		for _, v := range values {
518			if strings.TrimSpace(v) != "" {
519				return v
520			}

520			}
521		}
522		return ""
523	}
